const html = $input.first().json.data || $input.first().json;
const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);
const anchorRegex = /<a\s[^>]*class="[^"]*event-list-entry[^"]*"[^>]*>[\s\S]*?<\/a>/g;
const hrefRegex = /href="(https:\/\/www\.joyclub\.de\/event\/(\d+)\/[^"]+)"/;
const nameRegex = /class="inner ellipsis headline-status"[^>]*title="([^"]+)"/;
const dateRegex = /class="ela-date[^"]*">([^<]+)<\/span>/;
const results = [];
let match;
while ((match = anchorRegex.exec(htmlStr)) !== null) {
  const block = match[0];
  const hrefMatch = hrefRegex.exec(block);
  const nameMatch = nameRegex.exec(block);
  const dateMatch = dateRegex.exec(block);
  if (!hrefMatch) continue;
  if (block.includes('>Abgesagt<')) continue;
  const link = hrefMatch[1];
  const rawName = nameMatch ? nameMatch[1] : '';
  const rawDate = dateMatch ? dateMatch[1].trim() : '';
  const datum = rawDate.replace(/^\w+\.?,?\s*/, '').trim();
  let isoDatum = '';
  const dm = datum.match(/(\d{2})\.(\d{2})\.(\d{4})/);
  if (dm) isoDatum = `${dm[3]}-${dm[2]}-${dm[1]}`;
  if (rawName && datum) results.push({ json: { EventName: rawName, EventDatum: datum, isoDatum, EventLink: link } });
}
return results.length > 0 ? results : [{ json: { error: 'Keine Events gefunden', htmlLength: htmlStr.length } }];

const scraped = $('HTML parsen').all().map(i => i.json);
const dbEvents = $input.first().json.list || [];
const scrapedLinks = new Set(scraped.map(e => e.EventLink));
const dbMap = new Map(dbEvents.map(e => [e.EventLink, e]));
const results = [];
for (const ev of scraped) { if (!dbMap.has(ev.EventLink)) results.push({ json: { ...ev, _action: 'create' } }); }
for (const ev of scraped) { const existing = dbMap.get(ev.EventLink); if (existing) results.push({ json: { ...ev, _action: 'update', _id: existing.Id } }); }
for (const ev of dbEvents) { if (!scrapedLinks.has(ev.EventLink)) results.push({ json: { ...ev, _action: 'deactivate', _id: ev.Id } }); }
return results;

